function qz_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function qz_json($v){if($v===null||$v==='')return[];if(is_array($v))return$v;$d=json_decode((string)$v,true);return is_array($d)?$d:[];}
function qz_norm($v){return strtolower(trim(preg_replace('/\s+/',' ',(string)$v)));}
function qz_pick($r,$keys,$def=''){foreach($keys as $k){if(isset($r[$k])&&trim((string)$r[$k])!=='')return$r[$k];}return$def;}
function qz_redirect($m,$u,$a,$q=null,$x=[]){$url='?mode='.urlencode($m).'&unit='.intval($u).'&assignment='.intval($a);if($q!==null)$url.='&q='.intval($q);foreach($x as$k=>$v)$url.='&'.urlencode($k).'='.urlencode((string)$v);header('Location: '.$url);exit;}
function qz_rows_from_data($data){$p=qz_json($data);$rows=[];if(!$p)return$rows;if(isset($p[0])&&is_array($p[0]))$rows=$p;foreach(['questions','items','data','words','sentences','pairs','lines']as$k){if(isset($p[$k])&&is_array($p[$k])){$rows=$p[$k];break;}}if(empty($rows)&&is_array($p))$rows=[$p];return$rows;}
function qz_is_scoreable_type($type){return in_array($type,['quiz','multiple_choice','video_comprehension','fillblank','fill_blank','fill_in_blank','writing_practice','question_answer','matching_lines','match','dictation','pronunciation','order_sentences','unscramble','listen_order','drag_drop','drag_drop_kids'],true);}
function qz_add_mc(&$out,$id,$question,$options,$correct,$image='',$questionType='text',$voiceId='josh',$audio='',$optionType='text'){$options=array_values(array_filter($options,fn($v)=>trim((string)$v)!==''));if(trim((string)$question)!==''&&count($options)>=2)$out[]=['id'=>$id,'type'=>'multiple_choice','question'=>$question,'options'=>$options,'correct'=>$correct,'audio'=>$audio,'image'=>$image,'question_type'=>$questionType==='listen'?'listen':'text','voice_id'=>in_array($voiceId,['josh','lily','candy'],true)?$voiceId:'josh','option_type'=>$optionType==='image'?'image':'text','pairs'=>[]];}
function qz_add_fill(&$out,$id,$question,$answer){if(trim((string)$question)!==''&&trim((string)$answer)!=='')$out[]=['id'=>$id,'type'=>'fill','question'=>$question,'options'=>[],'correct'=>$answer,'audio'=>'','image'=>'','pairs'=>[]];}
function qz_add_match(&$out,$id,$pairs,$question='Match each item with the correct option.'){$clean=[];foreach($pairs as$p){if(!is_array($p))continue;$l=qz_pick($p,['left','term','word','en','front','question','a','from']);$r=qz_pick($p,['right','match','translation','es','back','answer','b','to']);if($l!==''&&$r!=='')$clean[]=['left'=>$l,'right'=>$r];}if(count($clean)>=2)$out[]=['id'=>$id,'type'=>'match','question'=>$question,'options'=>[],'correct'=>'','audio'=>'','image'=>'','pairs'=>$clean];}
function qz_add_pron(&$out,$id,$row){$word=qz_pick($row,['en','word','text','phrase','prompt','question']);$img=qz_pick($row,['img','image','image_url']);$audio=qz_pick($row,['audio','audio_url']);$ph=qz_pick($row,['ph','phonetic']);if($word!=='')$out[]=['id'=>$id,'type'=>'pronunciation','question'=>$word,'options'=>[],'correct'=>$word,'audio'=>$audio,'image'=>$img,'ph'=>$ph,'pairs'=>[]];}
function qz_normalize_activity($act){$rawType=strtolower(trim((string)($act['type']??'')));if(!qz_is_scoreable_type($rawType))return[];$payload=qz_json($act['data']??null);$rows=qz_rows_from_data($act['data']??null);$out=[];$base=(string)($act['id']??uniqid('qz_',true)); if($rawType==='quiz'||$rawType==='multiple_choice'||$rawType==='video_comprehension'){foreach($rows as$i=>$r){if(!is_array($r))continue;$opts=isset($r['options'])&&is_array($r['options'])?$r['options']:(isset($r['choices'])&&is_array($r['choices'])?$r['choices']:[$r['option_a']??'',$r['option_b']??'',$r['option_c']??'',$r['option_d']??'']);qz_add_mc($out,$base.'_'.$i,qz_pick($r,['question','prompt','text','title']),$opts,qz_pick($r,['correct','correct_answer','answer','expected'],0),qz_pick($r,['img','image','image_url']),qz_pick($r,['question_type'],'text'),qz_pick($r,['voice_id'],'josh'),qz_pick($r,['audio','audio_url']),qz_pick($r,['option_type'],'text'));}} elseif($rawType==='fillblank'||$rawType==='fill_blank'||$rawType==='fill_in_blank'||$rawType==='writing_practice'||$rawType==='question_answer'){foreach($rows as$i=>$r){if(!is_array($r))continue;qz_add_fill($out,$base.'_'.$i,qz_pick($r,['question','prompt','sentence','text','en']),qz_pick($r,['answer','correct','correct_answer','expected','es']));}} elseif($rawType==='matching_lines'||$rawType==='match'||$rawType==='listen_order'||$rawType==='drag_drop'||$rawType==='drag_drop_kids'){qz_add_match($out,$base.'_m',$rows,'Match each item with its correct pair.');} elseif($rawType==='pronunciation'){foreach($rows as$i=>$r)if(is_array($r))qz_add_pron($out,$base.'_'.$i,$r);} elseif($rawType==='order_sentences'||$rawType==='unscramble'){$voice=qz_pick($payload,['voice_id'],'josh');foreach($rows as$i=>$r){if(!is_array($r))continue;$sentence=qz_pick($r,['sentence','text','en','answer','correct']);if($sentence!==''){$tokens=array_values(array_filter(array_map(function($t){$clean=preg_replace('/^\d+[\.\)\-:]*/u','',trim((string)$t));return trim((string)$clean);},preg_split('/\s+/',trim($sentence))),fn($t)=>$t!==''));if(empty($tokens))continue;$listen=isset($r['listen_enabled'])?filter_var($r['listen_enabled'],FILTER_VALIDATE_BOOLEAN,FILTER_NULL_ON_FAILURE):true;$out[]=['id'=>$base.'_'.$i,'type'=>'unscramble','question'=>'Drag the words to make the sentence.','options'=>$tokens,'correct'=>implode(' ',$tokens),'audio'=>qz_pick($r,['audio','audio_url']),'image'=>qz_pick($r,['img','image','image_url']),'listen_enabled'=>$listen===null?true:(bool)$listen,'voice_id'=>$voice,'pairs'=>[]];}}} return$out;}
function qz_seed($u,$a,$att){$k='qz_seed_'.md5($u.'_'.$a.'_'.$att);if(!isset($_SESSION[$k]))$_SESSION[$k]=random_int(100000,999999);return(int)$_SESSION[$k];}
function qz_shuffle(&$arr,$seed){mt_srand($seed);for($i=count($arr)-1;$i>0;$i--){$j=mt_rand(0,$i);[$arr[$i],$arr[$j]]=[$arr[$j],$arr[$i]];}mt_srand();}
function qz_build($all,$u,$a,$att){$order=['pronunciation','multiple_choice','drag_drop','match','unscramble','fill'];$alias=['drag_drop'=>'match'];$by=[];foreach($all as$q)$by[$q['type']][]=$q;$seed=qz_seed($u,$a,$att);foreach($by as$t=>&$list){qz_shuffle($list,$seed+crc32($t));$limit=6;if($t==='unscramble')$limit=max(1,min(6,(int)ceil(count($list)*0.75)));$list=array_slice($list,0,$limit);}unset($list);$final=[];foreach($order as$t){$key=$alias[$t]??$t;if(!empty($by[$key])){foreach($by[$key] as$q){$q['block_type']=$t;$final[]=$q;}unset($by[$key]);}}foreach($by as$t=>$list)foreach($list as$q){$q['block_type']=$t;$final[]=$q;}return$final;}
function qz_correct($q,$a){if($a===null||$a==='')return false;if($q['type']==='pronunciation')return !empty($a);if($q['type']==='unscramble')return qz_norm($a)===qz_norm($q['correct']);if($q['type']==='match'){if(!is_array($a))return false;foreach($q['pairs']as$i=>$p)if(!isset($a[$i])||(string)$a[$i]!== (string)$p['right'])return false;return true;}if($q['type']==='multiple_choice'){if(is_numeric($q['correct']))return(string)$a===(string)$q['correct'];$opts=$q['options'];return isset($opts[(int)$a])&&qz_norm($opts[(int)$a])===qz_norm($q['correct']);}return qz_norm($a)===qz_norm($q['correct']);}
$unitId=isset($_GET['unit'])?intval($_GET['unit']):0;$assignment=isset($_GET['assignment'])?intval($_GET['assignment']):0;$mode=$_GET['mode']??'intro';$qIndex=isset($_GET['q'])?intval($_GET['q']):0;$returnTo=isset($_GET['return_to'])?trim((string)$_GET['return_to']):'';if(!$unitId)die('Missing unit id.');$pdo=get_pdo();$st=$pdo->prepare('SELECT * FROM activities WHERE unit_id=:u ORDER BY id ASC');$st->execute(['u'=>$unitId]);$activities=$st->fetchAll(PDO::FETCH_ASSOC);$all=[];foreach($activities as$act)foreach(qz_normalize_activity($act)as$q)$all[]=$q;if(!$all)die('<div style="font-family:Arial;padding:30px;color:#7c3aed"><h2>No scoreable quiz activities found for this unit.</h2></div>');$attKey='qz_attempt_'.$unitId.'_'.$assignment;if(!isset($_SESSION[$attKey]))$_SESSION[$attKey]=1;$att=(int)$_SESSION[$attKey];$setKey='qz_set_'.$unitId.'_'.$assignment.'_'.$att;$ansKey='qz_answers_'.$unitId.'_'.$assignment.'_'.$att;if(isset($_GET['reset'])){$_SESSION[$attKey]=$att+1;unset($_SESSION[$setKey],$_SESSION[$ansKey]);qz_redirect('intro',$unitId,$assignment,null,['return_to'=>$returnTo]);}if(!isset($_SESSION[$setKey]))$_SESSION[$setKey]=qz_build($all,$unitId,$assignment,$att);if(!isset($_SESSION[$ansKey]))$_SESSION[$ansKey]=[];$quiz=$_SESSION[$setKey];$answers=&$_SESSION[$ansKey];$total=count($quiz);
if($_SERVER['REQUEST_METHOD']==='POST'&&$mode==='quiz'){$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];if(isset($_POST['skip'])){$answers[$qIndex]=['answer'=>null,'skipped'=>true,'correct'=>false];$n=$qIndex+1;qz_redirect($n>=$total?'result':'quiz',$unitId,$assignment,$n>=$total?null:$n);} $ans=$q['type']==='match'?(isset($_POST['answer'])&&is_array($_POST['answer'])?$_POST['answer']:[]):($_POST['answer']??'');$ok=qz_correct($q,$ans);$answers[$qIndex]=['answer'=>$ans,'skipped'=>false,'correct'=>$ok];$n=$qIndex+1;qz_redirect($n>=$total?'result':'quiz',$unitId,$assignment,$n>=$total?null:$n);}
$labels=['pronunciation'=>['Pronunciation','Say the phrase','ti-microphone'],'multiple_choice'=>['Multiple choice','Pick the correct answer','ti-checks'],'fill'=>['Fill in the blank','Complete the sentence','ti-pencil'],'match'=>['Match','Connect each word to its pair','ti-arrows-shuffle'],'drag_drop'=>['Drag and drop','Arrange or match items','ti-hand-move'],'unscramble'=>['Unscramble','Put the words in order','ti-sort-ascending']];$counts=[];foreach($quiz as$q){$bt=$q['block_type']??$q['type'];$counts[$bt]=($counts[$bt]??0)+1;}$correct=0;$skip=0;foreach($answers as$a){if(!empty($a['correct']))$correct++;if(!empty($a['skipped']))$skip++;}$wrong=max(0,$total-$correct-$skip);$percent=$total?round($correct/$total*100):0;
$lastAnswered=count($answers)>0?max(array_keys($answers)):-1;$currentQuizIndex=max(0,min($total-1,$lastAnswered+1));$rtParam=$returnTo!==''?'&return_to='.urlencode($returnTo):'';$resultHref='?mode=result&unit='.$unitId.'&assignment='.$assignment.$rtParam;$reviewHref='?mode=review&unit='.$unitId.'&assignment='.$assignment.$rtParam;$quizHref='?mode=quiz&q='.$currentQuizIndex.'&unit='.$unitId.'&assignment='.$assignment.$rtParam;
