<?php elseif($mode==='quiz'):$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];$bt=$q['block_type']??$q['type'];$inf=$labels[$bt]??[$bt,'','ti-circle'];?><div class="screen-title">Pregunta <?php echo$qIndex+1;?> de <?php echo$total;?> Ã¢ÂÂ <?php echo qz_h($inf[0]);?></div><div class="card"><div class="progress-head"><span>PROGRESS</span><span><?php echo$qIndex+1;?> / <?php echo$total;?></span></div><div class="track"><div class="bar" style="width:<?php echo round((($qIndex+1)/$total)*100);?>%"></div></div><div class="tag"><i class="ti <?php echo qz_h($inf[2]);?>"></i><?php echo qz_h($inf[0]);?></div><?php if($q['type']==='pronunciation'):?><div class="pron-card"><div class="pron-listen-cue">Listen first</div><div class="pron-image"><?php if(!empty($q['image'])):?><img src="<?php echo qz_h($q['imaage']);?>" alt="<?php echo qz_h($q['correct']);?>"><?php else:?><div class="pron-word"><?php echo qz_h($q['correct']);?></div><?php endif;?></div><?php if(empty($q['image'])):?><div class="pron-word"><?php echo qz_h($q['correct']);?></div><?php endif;?><div class="pron-box pron-captured" id="pron-captured"></div></div><form method="post" id="pron-form"><input type="hidden" name="answer" id="pron-answer" value=""><div class="pron-actions"><button type="button" class="pron-btn pron-purple" id="pron-listen">Listen</button><button type="button" class="pron-btn pron-purple" id="pron-speak">Speaker</button><button type="submit" class="pron-btn pron-purple" name="skip" value="1" formnovalidate>Skip</button></div></form><script>(function(){var expected=<?php echo json_encode((string)$q['correct']);?>;var audio=<?php echo json_encode((string)$q['audio']);?>;var cap=document.getElementById('pron-captured'),answer=document.getElementById('pron-answer'),form=document.getElementById('pron-form'),submitted=false;var currentAudio=null,isSpeaking=false,isPaused=false,utter=null;function norm(t){return String(t||'').toLowerCase().trim().replace(/[.,!?;:'"-]/g,'').replace(/\s+/g,' ')}function overlap(a,b){var wa=a.split(' ').filter(Boolean),wb=b.split(' ').filter(Boolean);if(!wa.length||!wb.length)return 0;var m=wa.filter(function(w){return wb.indexOf(w)!==-1}).length;return m/Math.max(wa.length,wb.length)}function isMatch(a,b){return a===b||overlap(a,b)>=.8}function submit(ok){if(submitted)return;submitted=true;answer.value=ok?'1':'';setTimeout(function(){form.submit()},250)}function label(){var b=document.getElementById('pron-listen');if(b)b.textContent=isPaused?'Resume':(isSpeaking?'Pause':'Listen')}function voice(){var vs=[];try{vs=speechSynthesis.getVoices()||[]}catch(e){};for(var i=0;i<vs.length;i++)if(String(vs[i].lang||'').toLowerCase()==='en-us')return vs[i];for(var j=0;j<vs.length;j++)if(String(vs[j].lang||'').toLowerCase().indexOf('en')===0)return vs[j];return null}function listen(){if(audio){if(!currentAudio){currentAudio=new Audio(audio);currentAudio.onended=function(){isSpeaking=false;isPaused=false;label()}}if(!currentAudio.paused){currentAudio.pause();isSpeaking=true;isPaused=true}else{currentAudio.play();isSpeaking=true;isPaused=false}label();return}if(!window.speechSynthesis)return;if(speechSynthesis.speaking&&!speechSynthesis.paused){speechSynthesis.pause();isSpeaking=true;isPaused=true;label();return}if(speechSynthesis.paused||isPaused){speechSynthesis.resume();isSpeaking=true;isPaused=false;label();return}speechSynthesis.cancel();utter=new SpeechSynthesisUtterance(expected);utter.lang='en-US';utter.rate=.82;utter.pitch=1;var v=voice();if(v)utter.voice=v;utter.onstart=function(){isSpeaking=true;isPaused=false;label()};utter.onend=function(){isSpeaking=false;isPaused=false;label()};speechSynthesis.speak(utter)}function speak(){var C=window.SpeechRecognition||window.webkitSpeechRecognition;if(!C){cap.textContent='Speech recognition is not available in this browser.';submit(false);return}var r=new C();r.lang='en-US';r.interimResults=false;r.maxAlternatives=1;r.continuous=false;cap.textContent='Listening...';r.onresult=function(e){var said=String(e.results&&e.results[0]&&e.results[0][0]?e.results[0][0].transcript:'');var ok=isMatch(norm(said),norm(expected));cap.textContent='You said: '+said;submit(ok)};r.onerror=function(){cap.textContent='Try again.';submit(false)};r.start()}document.getElementById('pron-listen').onclick=listen;document.getElementById('pron-speak').onclick=speak;})();</script><?php elseif($q['type']==='multiple_choice'):?><?php $qzMcListen=($q['question_type']??'text')==='listen';$qzMcImageOptions=($q['option_type']??'text')==='image';?><form method="post" id="mc-form"><?php if($qzMcListen):?><div style="margin-bottom:12px;"><button type="button" class="btn btn-light" id="qz-mc-listen">🔊 Listen</button></div><?php else:?><div class="question"><?php echo qz_h($q['question']);?></div><?php endif;?><?php if(!empty($q['image'])):?><div style="margin-bottom:14px;"><img src="<?php echo qz_h($q['image']);?>" alt="Question image" style="width:100%;max-height:220px;object-fit:contain;border-radius:14px;border:1px solid var(--line);background:#fff;"></div><?php endif;?><?php foreach($q['options']as$i=>$op):?><label class="option"><input type="radio" name="answer" value="<?php echo$i;?>" onchange="setTimeout(function(){document.getElementById('mc-form').submit()},180)"><span class="letter"><?php echo chr(65+$i);?></span><?php if($qzMcImageOptions):?><img src="<?php echo qz_h($op);?>" alt="Option <?php echo chr(65+$i);?>" style="max-width:100%;max-height:120px;object-fit:contain;border-radius:10px;"><?php else:?><?php echo qz_h($op);?><?php endif;?></label><?php endforeach;?><div class="actions"><button class="btn btn-light" type="submit" name="skip" value="1" formnovalidate>Skip</button></div></form><?php if($qzMcListen):?><script>(function(){var b=document.getElementById('qz-mc-listen');if(!b)return;var text=<?php echo json_encode((string)$q['question']);?>;var audioUrl=<?php echo json_encode((string)($q['audio']??''));?>;var u=null,a=null;function stop(){if(a){a.pause();a.currentTime=0;a=null;}try{if(window.speechSynthesis){window.speechSynthesis.cancel();}}catch(e){}}function speak(){if(!text)return;stop();if(audioUrl){a=new Audio(audioUrl);a.play().catch(function(){});return;}if(!window.speechSynthesis)return;u=new SpeechSynthesisUtterance(text);u.lang='en-US';u.rate=.85;window.speechSynthesis.speak(u);}b.addEventListener('click',speak);setTimeout(speak,150);window.addEventListener('beforeunload',stop);})();</script><?php endif;?><?php elseif($q['type']==='unscramble'):?><?php
$qzTokens = $q['options'];
$qzShuffled = $qzTokens;
qz_shuffle($qzShuffled, qz_seed($unitId,$assignment,$att)+$qIndex+991);
?>
<form method="post" id="us-form">
  <input type="hidden" name="answer" id="us-answer" value="">
  <?php if(!empty($q['listen_enabled'])):?><div style="margin-bottom:12px;"><button type="button" class="btn btn-light" id="qz-us-listen">🔊 Listen</button></div><?php endif;?>
  <?php if(!empty($q['image'])):?><div style="margin-bottom:14px;"><img src="<?php echo qz_h($q['image']);?>" alt="Unscramble image" style="width:100%;max-height:220px;object-fit:contain;border-radius:14px;border:1px solid var(--line);background:#fff;"></div><?php endif;?>
  <div class="question"><?php echo qz_h($q['question']);?></div>

  <!-- Build area -->
  <div id="qz-build-area" class="qz-build-area">
    <span class="qz-build-placeholder" id="qz-build-ph">Drag words here to build the sentenceÂ¦</span>
  </div>

  <!-- Word bank -->
  <div id="qz-word-bank" class="qz-word-bank">
    <?php foreach($qzShuffled as $tok):?>
    <span class="qz-chip qz-bank-chip" draggable="true" data-word="<?php echo qz_h($tok);?>"><?php echo qz_h($tok);?></span>
    <?php endforeach;?>
  </div>

  <div id="qz-us-feedback" class="qz-us-feedback"></div>

  <div class="actions">
    <button type="button" class="btn btn-purple" id="qz-us-next">Next</button>
    <button class="btn btn-light" type="submit" name="skip" value="1" formnovalidate>Skip</button>
  </div>
</form>
<script>(function(){
var correct=<?php echo json_encode(qz_norm($q['correct']));?>;
var form=document.getElementById('us-form');
var ans=document.getElementById('us-answer');
var buildArea=document.getElementById('qz-build-area');
var wordBank=document.getElementById('qz-word-bank');
var feedback=document.getElementById('qz-us-feedback');
var nextBtn=document.getElementById('qz-us-next');
var listenBtn=document.getElementById('qz-us-listen');
var placeholder=document.getElementById('qz-build-ph');
var correctWords=correct.split(' ').filter(Boolean);
var attempts=0;var locked=false;var submitted=false;var dragged=null;
var listenText=<?php echo json_encode((string)$q['correct']);?>;
var listenAudio=<?php echo json_encode((string)($q['audio']??''));?>;
var listenPlayer=null;

function norm(t){return String(t||'').toLowerCase().trim().replace(/\s+/g,' ');}
function getBuilt(){return Array.from(buildArea.querySelectorAll('.qz-built-chip,.qz-correct-chip,.qz-wrong-chip')).map(function(c){return norm(c.dataset.word||c.textContent.trim());});}
function updatePlaceholder(){placeholder.style.display=buildArea.querySelectorAll('.qz-built-chip,.qz-correct-chip,.qz-wrong-chip').length?'none':'inline';}
function speakSentence(){if(!listenText)return;try{if(listenPlayer){listenPlayer.pause();listenPlayer.currentTime=0;listenPlayer=null;}if(window.speechSynthesis)window.speechSynthesis.cancel();}catch(e){} if(listenAudio){listenPlayer=new Audio(listenAudio);listenPlayer.play().catch(function(){});return;} if(!window.speechSynthesis)return;var u=new SpeechSynthesisUtterance(listenText);u.lang='en-US';u.rate=.85;window.speechSynthesis.speak(u);}

function createBankChip(word){
  var c=document.createElement('span');c.className='qz-chip qz-bank-chip';c.draggable=true;c.dataset.word=word;c.textContent=word;
  c.addEventListener('dragstart',function(e){dragged=c;c.dataset.src='bank';if(e.dataTransfer)e.dataTransfer.effectAllowed='move';});
  c.addEventListener('click',function(){if(locked)return;var b=createBuiltChip(word);buildArea.appendChild(b);c.remove();updatePlaceholder();setTimeout(autoCheck,40);});
  return c;
}
function createBuiltChip(word){
  var c=document.createElement('span');c.className='qz-chip qz-built-chip';c.draggable=true;c.dataset.word=word;c.textContent=word;
  c.addEventListener('dragstart',function(e){dragged=c;c.dataset.src='build';if(e.dataTransfer)e.dataTransfer.effectAllowed='move';});
  c.addEventListener('click',function(){if(locked)return;var b=createBankChip(word);wordBank.appendChild(b);c.remove();updatePlaceholder();feedback.textContent='';feedback.className='qz-us-feedback';});
  return c;
}

buildArea.addEventListener('dragover',function(e){e.preventDefault();buildArea.classList.add('qz-drag-over');});
buildArea.addEventListener('dragleave',function(){buildArea.classList.remove('qz-drag-over');});
buildArea.addEventListener('drop',function(e){
  e.preventDefault();buildArea.classList.remove('qz-drag-over');
  if(!dragged||locked)return;
  if(dragged.dataset.src==='bank'){buildArea.appendChild(createBuiltChip(dragged.dataset.word));dragged.remove();}
  else{buildArea.appendChild(dragged);}
  dragged=null;updatePlaceholder();setTimeout(autoCheck,40);
});
wordBank.addEventListener('dragover',function(e){e.preventDefault();});
wordBank.addEventListener('drop',function(e){
  e.preventDefault();
  if(!dragged||locked)return;
  if(dragged.dataset.src==='build'){wordBank.appendChild(createBankChip(dragged.dataset.word));dragged.remove();updatePlaceholder();feedback.textContent='';feedback.className='qz-us-feedback';}
  dragged=null;
});

function checkNow(){
  if(locked)return;
  var built=getBuilt();
  if(built.length<correctWords.length){feedback.textContent='Place all words first.';feedback.className='qz-us-feedback bad';return;}
  attempts++;
  var isOk=JSON.stringify(built)===JSON.stringify(correctWords);
  if(isOk){
    feedback.textContent='â Correct!';feedback.className='qz-us-feedback good';
    locked=true;
    buildArea.querySelectorAll('.qz-built-chip').forEach(function(c){c.className='qz-chip qz-correct-chip';c.draggable=false;});
    ans.value=built.join(' ');
    setTimeout(function(){if(!submitted){submitted=true;form.submit();}},600);
  } else if(attempts>=2){
    feedback.textContent='â Incorrect â see correct order';feedback.className='qz-us-feedback bad';
    locked=true;
    // color chips by position
    var chips=Array.from(buildArea.querySelectorAll('.qz-built-chip'));
    chips.forEach(function(c,i){c.className='qz-chip '+(norm(c.dataset.word||'')===(correctWords[i]||'')?'qz-correct-chip':'qz-wrong-chip');c.draggable=false;});
    ans.value=built.join(' ');
  } else {
    feedback.textContent='â Not quite â try again (1/2)';feedback.className='qz-us-feedback bad';
  }
}

function autoCheck(){
  if(locked)return;
  var built=getBuilt();
  if(built.length<correctWords.length)return;
  checkNow();
}

nextBtn.addEventListener('click',function(){
  if(submitted)return;submitted=true;
  var built=getBuilt();ans.value=built.join(' ');
  form.submit();
});

// Init bank chips with events
Array.from(wordBank.querySelectorAll('.qz-bank-chip')).forEach(function(c){
  c.addEventListener('dragstart',function(e){dragged=c;c.dataset.src='bank';if(e.dataTransfer)e.dataTransfer.effectAllowed='move';});
  c.addEventListener('click',function(){if(locked)return;var b=createBuiltChip(c.dataset.word);buildArea.appendChild(b);c.remove();updatePlaceholder();setTimeout(autoCheck,40);});
});
if(listenBtn){listenBtn.addEventListener('click',speakSentence);setTimeout(speakSentence,150);}
})();</script><?php elseif($q['type']==='match'):?><form method="post"><div class="question"><?php echo qz_h($q['question']);?></div><div class="match-grid"><?php $rights=array_column($q['pairs'],'right');foreach($q['pairs']as$i=>$p):?><div class="match-left"><?php echo qz_h($p['left']);?></div><select class="select" name="answer[<?php echo$i;?>]" required><option value="">Choose</option><?php foreach($rights as$r):?><option value="<?php echo qz_h($r);?>"><?php echo qz_h($r);?></option><?php endforeach;?></select><?php endforeach;?></div><div class="actions"><button class="btn btn-purple" type="submit">Next</button><button class="btn btn-light" type="submit" name="skip" value="1" formnovalidate>Skip</button></div></form><?php else:?><form method="post"><div class="question"><?php echo qz_h($q['question']);?></div><input class="input" name="answer" required autocomplete="off" placeholder="Type your answer"><div class="actions"><button class="btn btn-purple" type="submit">Next</button><button class="btn btn-light" type="submit" name="skip" value="1" formnovalidate>Skip</button></div></form><?php endif;?></div>
<?php elseif($mode==='result'):?><div class="screen-title">Resultado</div><div class="card"><div class="result-hero"><div class="pct"><?php echo$percent;?>%</div><div class="lead">Quiz complete</div><span class="pill" style="background:#eafff3;color:#07823f"><?php echo$correct;?> correct</span><span class="pill" style="background:#fff0f0;color:#c82020"><?php echo$wrong;?> wrong</span><span class="pill" style="background:#f0ecff;color:#8070dd"><?php echo$skip;?> skipped</span></div><div class="actions"><a class="btn btn-purple" href="<?php echo qz_h($reviewHref);?>">Review</a><a class="btn btn-light" href="?reset=1&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?><?php if($returnTo!=='')echo'&return_to='.urlencode($returnTo);?>">Try again</a></div></div><?php elseif($mode==='review'):?><div class="screen-title">Review</div><div class="card"><?php foreach($quiz as$i=>$q):$a=$answers[$i]??null;?><div class="review"><b><?php echo$i+1;?>. <?php echo qz_h($q['question']);?></b><br><small><?php echo!empty($a['correct'])?'Correct':'0 points';?></small></div><?php endforeach;?></div><?php endif;?> <script src="fill_fix.js"></script> </div></body></html>
